// 
import React, { useEffect } from "react";
import UserLayout from "@/layout/UserLayout";
import DashboardLayout from "@/layout/DashboardLayout";
import { getMyConnectionRequest } from "@/config/redux/action/authAction";
import { useDispatch, useSelector } from "react-redux";
import styles from "./index.module.css";
import { BASE_URL } from "@/config";
import { useRouter } from "next/router";

export default function MyConnections() {
  const dispatch = useDispatch();
  const authState = useSelector((state) => state.auth);

  useEffect(() => {
    dispatch(getMyConnectionRequest({ token: localStorage.getItem("token") }));
  }, []);
  const router = useRouter();
  useEffect(() => {
    if (authState.connectionRequests.length !== 0) {
      console.log(authState.connectionRequests);
    }
  }, [authState.connectionRequests]);

  return (
    <UserLayout>
      <DashboardLayout>
        <div className={styles.connectionsContainer}>
          <h1 className={styles.heading}>Connection Requests</h1>
          {authState.connectionRequests.length ===0 && <h1>No Connection Request</h1>}
          {authState.connectionRequests.length !== 0 &&
            authState.connectionRequests.map((user, index) => (
              <div onClick={()=>{
                router.push(`/view_profile/${user.userId.username}`)
              }} className={styles.userCard} key={index}>
                <div className={styles.leftSection}>
                  <div className={styles.profilePicture}>
                    <img
                      src={`${BASE_URL}/${user.userId.profilePicture}`}
                      alt={user.userId.name}
                    />
                  </div>
                  <div className={styles.userInfo}>
                    <h3>{user.userId.name}</h3>
                    <p>@{user.userId.username}</p>
                    <span>Software Developer</span>
                  </div>
                </div>

                <div className={styles.buttonGroup}>
                  <button className={styles.connectButton}>Accept</button>
                  <button className={styles.ignoreBtn}>Ignore</button>
                </div>
              </div>
            ))}
        </div>
      </DashboardLayout>
    </UserLayout>
  );
}







